INSERT INTO products VALUES
  (1, "MyPad", "MyPad", "Modern Text Editor", "Modern Text Editor", "\"毎日使うものこそ、美しく便利なものを...\" そんな想いで作られたテキストエディタが MyPad です。視認性に優れるモダンな外観に、使い慣れたクラシックな操作性を兼ね備え、様々な用途にご利用頂けます。", "\"Something you use every day should be beautiful and useful...\" MyPad is a text editor created with this in mind. MyPad combines a modern, highly readable appearance with familiar, classic operability, and can be used for a variety of purposes.", "csharp, dotnet, wpf, prism, mahapps, win32, wap", "https://github.com/kawasawa/MyPad", "https://apps.microsoft.com/store/detail/9PP2600ZM2JD", 6000, true, true),
  (2, "ひより", "HIYORI", "Weather Forecast", "Weather Forecast", "気象情報を一覧できる Web サイトです。現在位置における直近から数日先までの三時間ごとの天気、気温、湿度、風の情報をまとめて確認できます。", "This Web site provides a list of weather information. You can check the weather, temperature, humidity, and wind information for the last three hours at your current location and for the next few days.", "typescript, reactjs, mui, pwa, leaflet", "https://github.com/kawasawa/hiyori", "https://kawasawa.github.io/hiyori", null, true, true),
  (3, "工具箱", "Toolbox", "Development Toolkit", "Development Toolkit", "開発者向けの簡易ツールです。文字列のケース変換やハッシュ化、Base変換などに対応しています。すべての処理はブラウザ内で行われ、データは外部に送信されません。", "This is a simple tool for developers. It supports string case conversion, hashing, Base conversion, etc. All processing is done within the browser and no data is sent externally.", "go, wasm, javascript", "https://github.com/kawasawa/go-wasm-toys", "https://kawasawa.github.io/go-wasm-toys", null, true, true),
  (4, "こよみ", "KOYOMI", "Japanese Calendar", "Japanese Calendar", "暦の情報を一覧できる Web サイトです。旧暦や六曜のほか二十四節気、星座、干支、月相などの暦注を確認できます。", "This Web site provides a list of calendar information. In addition to the lunar calendar and the six days of the week, you can check the 24 solar terms, zodiac signs, zodiac signs, lunar phases, and other calendar notes.", "typescript, reactjs, mui, pwa", "https://github.com/kawasawa/koyomi", "https://kawasawa.github.io/koyomi", null, false, true),
  (5, "MyBase", "MyBase", "Development Library", "Development Library", "MyBase は .NET Framework, .NET Core による WPF アプリケーションの開発をサポートするためのライブラリです。Prism と連携し標準機能を拡張する処理や、最新の Prism では廃止されてしまった実装の一部が移植されています。", "MyBase is a library to support the development of WPF applications with .NET Framework, .NET Core, and includes a process to extend the standard functionality in conjunction with Prism, as well as a port of some implementations that are deprecated in the latest version of Prism.", "csharp, dotnetcore, prism, nuget", "https://github.com/kawasawa/MyBase", "https://www.nuget.org/packages/MyBase", 1800, false, true)
