INSERT INTO articles_metadata VALUES
  ('5a6dee26db36aa83915f', '[覚書] MVVM の定義', '## はじめに 忘れないように戒めの覚え書き。 以下、すべて独学のオレオレ MVVM で、原理原則から逸脱している部分もあるはず... あくまで個人的にはですが、使えるなら細かい定義は気にしない考えで...', 'MVVM', 'https://qiita.com/kawasawa/items/5a6dee26db36aa83915f', 10, 4, 0, '2020-04-14T23:24:23+09:00', '2020-08-09T08:22:24+09:00'),
  ('1c40b596838c2e9e24f3', 'View を支えるコンバーター', '## はじめに 戒めの覚え書き　その２ 今回は MVVM の View 層について少し掘り下げます。 View 層に定義されるロジックは描画や表示に関わるものが基本となり、この実装をサポートするための...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/1c40b596838c2e9e24f3', 4, 1, 0, '2020-04-16T21:06:15+09:00', '2020-04-17T22:40:25+09:00'),
  ('d2ba3b9152be719bf364', 'View を支えるコンバーター（QuickConverter）', '## はじめに オレオレ解釈の戒め覚え書き　その３ [前回](https://qiita.com/kawasawa/items/1c40b596838c2e9e24f3)に続きコンバーターの話です。強...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/d2ba3b9152be719bf364', 4, 4, 0, '2020-04-17T23:47:17+09:00', '2020-04-18T22:23:05+09:00'),
  ('f373e45eeafd67fd23ff', 'View を支えるビヘイビア', '## はじめに オレオレ解釈の戒め覚え書き　その４ 今回はビヘイビアについてです。 ※Expression Blend に付属していた所謂 BlendBehavior と呼ばれているビヘイビアについて...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/f373e45eeafd67fd23ff', 4, 4, 0, '2020-04-20T21:39:04+09:00', '2020-06-24T19:27:25+09:00'),
  ('bbd5efe79d2e712686cd', 'View を支えるトリガーアクション', '## はじめに オレオレ解釈の覚え書き　その５ トリガーアクションについてです。 ※今回も Expression Blend に付属する Trigger, Action について触れていきます。 ##...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/bbd5efe79d2e712686cd', 3, 5, 0, '2020-04-21T23:11:23+09:00', '2020-04-21T23:11:23+09:00'),
  ('5237aeb8610458e9a2d2', 'ViewModel と相互作用処理', '## はじめに オレオレ解釈の覚え書き　その６ 今回から ViewModel のお話です。ここでは相互作用処理についてまとめます。 ## 本文 MVVM における相互作用処理とはユーザとの対話が発生す...', 'C#, .NET, Xaml, MVVM, PRISM', 'https://qiita.com/kawasawa/items/5237aeb8610458e9a2d2', 3, 2, 1, '2020-04-27T23:14:59+09:00', '2020-04-28T06:38:21+09:00'),
  ('bd8c238f8f1d6a88e932', 'ViewModel と相互作用処理（DialogService）', '## はじめに オレオレ解釈の覚え書き　その７ 引き続き相互作用処理についての内容で、Prism 7.2 から採用された DialogService を使ったダイアログ表示の実装方法をまとめます。なお...', 'C#, .NET, Xaml, MVVM, PRISM', 'https://qiita.com/kawasawa/items/bd8c238f8f1d6a88e932', 8, 1, 1, '2020-05-09T16:33:38+09:00', '2020-05-28T22:55:35+09:00'),
  ('11b5f090a302d5832fde', 'ViewModel と移譲コマンド', '## はじめに オレオレ解釈の覚え書き　その８ 移譲コマンドについてまとめます。 ## 本文 移譲コマンドとは ViewModel で宣言されるデリゲートです。View からバインドされることを前提に...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/11b5f090a302d5832fde', 2, 1, 0, '2020-05-28T23:30:17+09:00', '2020-05-28T23:30:17+09:00'),
  ('c2c15d402eaf6ce08d61', 'ViewModel と変更通知プロパティ', '## はじめに オレオレ解釈の覚え書き　その９ 一番最初にやるべきだった変更通知プロパティについてまとめます。 タイトルには「ViewModel と～」とありますが、Model 層で使用される場合もあ...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/c2c15d402eaf6ce08d61', 10, 7, 0, '2020-06-03T23:48:15+09:00', '2020-06-04T08:32:42+09:00'),
  ('ec8d2a5589133cf63f74', 'ViewModel と変更通知プロパティ（ReactiveProperty）', '## はじめに オレオレ解釈の覚え書き　その１０ 変更通知プロパティの話から派生して、強力なライブラリである ReactiveProperty についてご紹介します。 ## 本文 前回ご紹介した変更通...', 'C#, .NET, Xaml, MVVM, ReactiveProperty', 'https://qiita.com/kawasawa/items/ec8d2a5589133cf63f74', 6, 2, 0, '2020-06-17T00:56:40+09:00', '2020-06-17T15:57:44+09:00'),
  ('1791950b687cd60efa86', 'View を支える依存関係プロパティ', '## はじめに オレオレ解釈の覚書　その１１ 依存関係プロパティについてです。 ## 本文 依存関係プロパティとは簡単に言えば Xaml 上でバインドできるコントロールのプロパティです。身近なところで...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/1791950b687cd60efa86', 4, 5, 4, '2020-06-24T12:26:41+09:00', '2020-06-24T19:22:16+09:00'),
  ('36c18fdb512cc1bcbd54', 'View を支える添付プロパティ', '## はじめに オレオレ解釈の覚書　その１２ 依存関係プロパティに関連して、添付プロパティのまとめです。 ## 本文 添付プロパティも実体は依存関係プロパティと同じ DependencyPropert...', 'C#, .NET, Xaml, MVVM', 'https://qiita.com/kawasawa/items/36c18fdb512cc1bcbd54', 4, 3, 0, '2020-06-24T19:32:04+09:00', '2020-06-24T19:32:04+09:00'),
  ('8d31e2678fb87c1d825e', 'ViewModel と相互作用処理（Messanger）', '## はじめに オレオレ解釈の覚書　その１３ Livet に用意された相互作用処理のため実装である Messanger についてまとめます。 ## 本文 [前回](https://qiita.com/...', 'C#, .NET, Xaml, MVVM, Livet', 'https://qiita.com/kawasawa/items/8d31e2678fb87c1d825e', 3, 1, 0, '2020-08-08T18:20:44+09:00', '2020-08-12T19:29:05+09:00'),
  ('888898c78ce37c6bc43c', '[覚書] MVVM の各層と配置', 'これもオレオレ解釈ですが、 覚え書きで挙げていた MVVM の各層と構成要素、サードパーティーの配置、それぞれの役割を一旦まとめると、以下の図のようになります（と思っています）。 実際にプログラムを書...', 'MVVM, PRISM', 'https://qiita.com/kawasawa/items/888898c78ce37c6bc43c', 4, 3, 0, '2020-08-19T00:45:55+09:00', '2020-08-23T20:14:58+09:00'),
  ('752865e571cbb4b6526f', 'AvalonEdit の改行マークを変更したい', '## はじめに 今回は小ネタです。この記事は AvalonEdit のカスタマイズを試みた際の備忘録です。 [自作のメモ帳アプリ](https://www.microsoft.com/ja-jp/p/...', 'C#, WPF, 小ネタ, AvalonEdit', 'https://qiita.com/kawasawa/items/752865e571cbb4b6526f', 4, 2, 0, '2020-08-30T00:10:05+09:00', '2020-08-31T19:45:02+09:00'),
  ('45b5969c49084bd34a91', 'WPF 開発が捗る 神７', '## はじめに 独学で習得してきた WPF ですが、決定的な指針が無く、開発が手探りになりがちでした。日本語の文献は少なく、ブログ等で有識者の手法を真似て実装しますが、流行り廃りが早いためなかなか環境...', 'WPF, 雑記', 'https://qiita.com/kawasawa/items/45b5969c49084bd34a91', 118, 119, 3, '2020-10-30T11:45:03+09:00', '2021-01-18T21:30:28+09:00'),
  ('d579da43536984a275ec', 'KeyTrigger に紐づけたコマンドが何回も発報する', '## 困りごと 私のための備忘録。 以下のように KeyTrigger とコマンドを紐づけたコントロールを用意し、それを TabControl->TabItem に置いてみたところ、掲題のようにコマン...', 'C#, WPF, 備忘録, PRISM', 'https://qiita.com/kawasawa/items/d579da43536984a275ec', 3, 2, 0, '2021-01-18T21:36:11+09:00', '2021-01-28T00:15:20+09:00'),
  ('18673e011265659beb64', 'WPF でサクッと多言語化したい、しかも動的に切り替えたい', '## はじめに WPF アプリケーションにおける動的な多言語対応について、サードパーティーの [WPFLocalizeExtension](https://www.nuget.org/packages...', 'C#, WPF, 雑記, Xaml, PRISM', 'https://qiita.com/kawasawa/items/18673e011265659beb64', 5, 12, 0, '2021-07-06T18:33:50+09:00', '2021-07-06T18:33:50+09:00'),
  ('80960c415a972219d8e1', 'デスクトップ開発出身者が 無料のサービスだけ使って Web 開発に触れてみる', '## はじめに 私は C#, WPF, .NET など Windows のデスクトップアプリ開発からスタートした人間で、Web 開発は体系的に学べておらず、実務で開発する機会があっても場当たり的な対応...', 'GitHub, Heroku, Express, TypeScript, React', 'https://qiita.com/kawasawa/items/80960c415a972219d8e1', 25, 14, 0, '2021-12-18T00:52:52+09:00', '2021-12-20T20:49:45+09:00')
